fn solve(words: Vec<String>) -> Vec<i64> {
    let n = words.len();
    let mut answer = vec![0; n];

    if n == 1 {
        return answer;
    }

    // Precompute the LCP between adjacent words in the original array
    let mut original_lcps = vec![0; n - 1];
    for i in 0..n - 1 {
        original_lcps[i] = common_prefix(&words[i], &words[i + 1]);
    }

    for i in 0..n {
        let mut max_lcp = 0;

        if n == 2 {
            // Only one pair left, which is either (0,1) or (1,0) depending on removal
            // But since we remove one, there are no adjacent pairs left
            answer[i] = 0;
            continue;
        }

        // Check the adjacent pairs that are affected by removing i
        // The affected pairs are (i-1, i) and (i, i+1) in the original array
        // After removal, the new adjacent pair is (i-1, i+1)
        let mut temp_lcps = Vec::new();

        // Copy all original_lcps except those involving i
        for j in 0..original_lcps.len() {
            if j != i && j != i.saturating_sub(1) {
                temp_lcps.push(original_lcps[j]);
            }
        }

        // Handle the new adjacent pair formed by (i-1, i+1) if applicable
        if i > 0 && i < n - 1 {
            let new_lcp = common_prefix(&words[i - 1], &words[i + 1]);
            temp_lcps.push(new_lcp);
        }

        // Find the maximum LCP in temp_lcps
        max_lcp = *temp_lcps.iter().max().unwrap_or(&0);
        answer[i] = max_lcp as i64;
    }

    answer
}

fn common_prefix(a: &str, b: &str) -> usize {
    let a_chars: Vec<char> = a.chars().collect();
    let b_chars: Vec<char> = b.chars().collect();
    let mut len = 0;
    let min_len = a_chars.len().min(b_chars.len());

    while len < min_len && a_chars[len] == b_chars[len] {
        len += 1;
    }

    len
}
