fn solve(words: Vec<String>) -> Vec<i64> {
    let n = words.len();
    let mut answer = vec![0; n];

    if n == 1 {
        return answer;
    }

    // Precompute the LCP between adjacent pairs in the original array
    let mut original_lcps = vec![0; n - 1];
    for i in 0..n - 1 {
        original_lcps[i] = common_prefix(&words[i], &words[i + 1]);
    }

    for i in 0..n {
        let mut max_lcp = 0;

        // Check the pair that is formed when removing i (i-1 and i+1)
        if i > 0 && i < n - 1 {
            let lcp = common_prefix(&words[i - 1], &words[i + 1]);
            if lcp > max_lcp {
                max_lcp = lcp;
            }
        }

        // Check the original adjacent pairs that are not affected by removing i
        if i > 0 {
            // The pair (i-2, i-1) is unaffected if i-2 >= 0
            if i - 2 >= 0 {
                let lcp = original_lcps[i - 2];
                if lcp > max_lcp {
                    max_lcp = lcp;
                }
            }
            // The pair (i-1, i) is removed, so we skip it
        } else {
            // If i == 0, original_lcps[1..] are unaffected
            if n > 2 {
                for &lcp in &original_lcps[1..] {
                    if lcp > max_lcp {
                        max_lcp = lcp;
                    }
                }
            }
        }

        if i < n - 1 {
            // The pair (i, i+1) is removed, so we skip it
            // The pair (i+1, i+2) is unaffected if i+2 < n
            if i + 2 < n {
                let lcp = original_lcps[i + 1];
                if lcp > max_lcp {
                    max_lcp = lcp;
                }
            }
        } else {
            // If i == n-1, original_lcps[..n-2] are unaffected
            if n > 2 {
                for &lcp in &original_lcps[..n - 2] {
                    if lcp > max_lcp {
                        max_lcp = lcp;
                    }
                }
            }
        }

        answer[i] = max_lcp as i64;
    }

    answer
}

fn common_prefix(a: &str, b: &str) -> usize {
    let a_chars: Vec<char> = a.chars().collect();
    let b_chars: Vec<char> = b.chars().collect();
    let mut len = 0;
    let min_len = std::cmp::min(a_chars.len(), b_chars.len());

    while len < min_len && a_chars[len] == b_chars[len] {
