        original_lcps[i] = common_prefix(&words[i], &words[i + 1]);
    }

    for i in 0..n {
        let mut max_lcp = 0;

        if n == 2 {
            // Only one pair left, and it's the same as original if i is not part of it
            if i == 0 || i == 1 {
                // Removing either leaves only one element, no pairs
                max_lcp = 0;
            }
        } else {
            // Check the pairs around the removed index
            if i > 0 && i < n - 1 {
                // The new pair is (i-1, i+1)
                let new_lcp = common_prefix(&words[i - 1], &words[i + 1]);
                max_lcp = new_lcp;
            }

            // Compare with other existing pairs not affected by the removal
            // Pairs before i-1
            if i > 0 {
                for j in 0..i - 1 {
                    if original_lcps[j] > max_lcp {
                        max_lcp = original_lcps[j];
                    }
                }
            }
            // Pairs after i+1
            if i < n - 1 {
                for j in i + 1..n - 1 {
                    if original_lcps[j] > max_lcp {
                        max_lcp = original_lcps[j];
                    }
                }
            }
        }

        answer[i] = max_lcp as i64;
    }

    answer
}

